entry.content:
在平常工作中有时候需要查看方法的调用时间，或者需要知道某个业务的调用逻辑，需要些大量侵入式代码来完成。现在可以使用javaagent在main方法前执行，然后加载的类，通过字节码技术，在类中加入需要的代码。 构建agent项目1、 新建maven jar项目pom.xml12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970&lt;project xmlns="http://maven.apache.org/POM/4.0.0" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance" xsi:schemaLocation="http://maven.apache.org/POM/4.0.0 http://maven.apache.org/xsd/maven-4.0.0.xsd"&gt; &lt;modelVersion&gt;4.0.0&lt;/modelVersion&gt; &lt;groupId&gt;com.whh&lt;/groupId&gt; &lt;artifactId&gt;javaagentdemo&lt;/artifactId&gt; &lt;version&gt;1.0-SNAPSHOT&lt;/version&gt; &lt;packaging&gt;jar&lt;/packaging&gt; &lt;name&gt;javaagentdemo&lt;/name&gt; &lt;url&gt;http://maven.apache.org&lt;/url&gt; &lt;properties&gt; &lt;project.build.sourceEncoding&gt;UTF-8&lt;/project.build.sourceEncoding&gt; &lt;/properties&gt; &lt;dependencies&gt; &lt;!-- &lt;dependency&gt; &lt;groupId&gt;org.apache.bcel&lt;/groupId&gt; &lt;artifactId&gt;bcel&lt;/artifactId&gt; &lt;version&gt;6.2&lt;/version&gt; &lt;/dependency&gt; --&gt; &lt;!-- 字节码增强 --&gt; &lt;dependency&gt; &lt;groupId&gt;org.javassist&lt;/groupId&gt; &lt;artifactId&gt;javassist&lt;/artifactId&gt; &lt;version&gt;3.21.0-GA&lt;/version&gt; &lt;/dependency&gt; &lt;/dependencies&gt; &lt;build&gt; &lt;plugins&gt; &lt;!-- 打包依赖jar --&gt; &lt;plugin&gt; &lt;groupId&gt;org.apache.maven.plugins&lt;/groupId&gt; &lt;artifactId&gt;maven-jar-plugin&lt;/artifactId&gt; &lt;configuration&gt; &lt;archive&gt; &lt;manifestFile&gt;src/main/resources/META-INF/MANIFEST.MF&lt;/manifestFile&gt; &lt;/archive&gt; &lt;/configuration&gt; &lt;/plugin&gt; &lt;plugin&gt; &lt;groupId&gt;org.apache.maven.plugins&lt;/groupId&gt; &lt;!-- 用这个maven打包插件 --&gt; &lt;artifactId&gt;maven-shade-plugin&lt;/artifactId&gt; &lt;version&gt;2.3&lt;/version&gt; &lt;executions&gt; &lt;execution&gt; &lt;phase&gt;package&lt;/phase&gt; &lt;goals&gt; &lt;goal&gt;shade&lt;/goal&gt; &lt;/goals&gt; &lt;/execution&gt; &lt;/executions&gt; &lt;/plugin&gt; &lt;plugin&gt; &lt;groupId&gt;org.apache.maven.plugins&lt;/groupId&gt; &lt;artifactId&gt;maven-compiler-plugin&lt;/artifactId&gt; &lt;version&gt;3.6.0&lt;/version&gt; &lt;configuration&gt; &lt;source&gt;1.8&lt;/source&gt; &lt;target&gt;1.8&lt;/target&gt; &lt;/configuration&gt; &lt;/plugin&gt; &lt;/plugins&gt; &lt;/build&gt;&lt;/project&gt; 2、 新建java文件、新增premain方法如下：12345public class PreMain &#123; public static void premain(String args, Instrumentation instrumentation)&#123; System.out.println("premain"); &#125;&#125; 3、resource下新建META-INF/MANIFEST.MF123Manifest-Version: 1.0Premain-Class: com.whh.PreMainCan-Redefine-Classes: true 注意的是最后是一个空行，没有会报错。 4、 打包生成jar5、 随便写一个Main启动测试、在启动时添加VM参数：-javaagent:javaagentdemo-1.0-SNAPSHOT.jar。会发现PreMain中premain会被执行。 字节码修改我们需要对加载的类做字节码修改，所以需要用到Instrumentation。新建类TransformerDemo. javassist.*;import java.io.IOException;import java.lang.instrument.ClassFileTransformer;import java.lang.instrument.IllegalClassFormatException;import java.security.ProtectionDomain;import java.util.ArrayList;import java.util.List;/** * TestTransformer * Created by whhxz on 2018/1/9. */public class TransformerDemo implements ClassFileTransformer &#123; private static ThreadLocal&lt;List&lt;MethodStackInfo&gt;&gt; inMethodStack = ThreadLocal.withInitial(ArrayList::new); /** * 方法调用前调用，记录进入方法时间 * @param className * @param method */ public static void startMethod(String className, String method) &#123; long now = System.currentTimeMillis(); MethodStackInfo methodStackInfo = new MethodStackInfo(className + "." + method); methodStackInfo.setStartTime(now); List&lt;MethodStackInfo&gt; inStack = inMethodStack.get(); if (inStack.size() == 0) &#123; methodStackInfo.setDepth(0); &#125; else &#123; for (int i = inStack.size() - 1; i &gt;= 0; i--) &#123; MethodStackInfo lastInStack = inStack.get(i); if (lastInStack.getEndTime() == 0) &#123; methodStackInfo.setDepth(lastInStack.getDepth() + 1); break; &#125; &#125; &#125; inStack.add(methodStackInfo); &#125; /** * 出方法时调用，记录出方法时间 * @param className * @param method */ public static void endMethod(String className, String method) &#123; long now = System.currentTimeMillis(); List&lt;MethodStackInfo&gt; inStack = inMethodStack.get(); for (int i = inStack.size() - 1; i &gt;= 0; i--) &#123; MethodStackInfo methodStackInfo = inStack.get(i); if (methodStackInfo. getEndTime() == 0) &#123; methodStackInfo.setEndTime(now); break; &#125; &#125; //最外层已经出栈，打印相关信息 if (inStack.get(0).getName().equals(className + "." + method)) &#123; for (MethodStackInfo methodStackInfo : inStack) &#123; StringBuilder sb = new StringBuilder(); sb.append("|"); for (int i = 0; i &lt; methodStackInfo.getDepth(); i++) &#123; sb.append(" |"); &#125; sb.append("__").append(methodStackInfo.getName()) .append(" :") .append(methodStackInfo.getEndTime() - methodStackInfo.getStartTime()) .append(" ms"); System.out.println(sb.toString()); &#125; inMethodStack.remove(); &#125; &#125; public byte[] transform(ClassLoader loader, String className, Class&lt;?&gt; classBeingRedefined, ProtectionDomain protectionDomain, byte[] classfileBuffer) throws IllegalClassFormatException &#123; className = className.replaceAll("/", "."); //过滤需要处理的类 if (!className.contains("com.whh.Main") || className.contains("$$")) &#123; return null; &#125; try &#123; //获取加载的字节码 ClassPool classPool = ClassPool.getDefault(); classPool.insertClassPath(new LoaderClassPath(loader)); CtClass ctClass = classPool.get(className); //修改方法字节码，新增插入的代码 CtMethod[] declaredMethods = ctClass.getDeclaredMethods(); for (CtMethod declaredMethod : declaredMethods) &#123; String methodName = declaredMethod.getName(); if (declaredMethod.isEmpty()) continue; declaredMethod.insertBefore("com.whh.transformer.TestTransformer.startMethod("" + className + "", "" + methodName + "");"); declaredMethod.insertAfter("com.whh.transformer.TestTransformer.endMethod("" + className + "", "" + methodName + "");", true); &#125; /*for (CtMethod declaredMethod : declaredMethods) &#123; String oldName = declaredMethod.getName(); declaredMethod.setName(oldName + "$old"); CtMethod newMethod = CtNewMethod.copy(declaredMethod, oldName, ctClass, null); StringBuilder sb = new StringBuilder(); sb.append("&#123;") .append("
long startTime = System.currentTimeMillis();
") .append(oldName).append("$old($$);
") .append("
long endTime = System.currentTimeMillis();
") .append("
System.out.println("~~~~~~~~this method ") .append(oldName) .append(" cost:" +(endTime - startTime) +"ms.");") .append("&#125;"); newMethod.setBody(sb.toString()); ctClass.addMethod(newMethod); &#125;*/ return ctClass.toBytecode(); &#125; catch (NotFoundException | CannotCompileException | IOException e) &#123; System.out.println("~~~~~~~~~~" + className); e.printStackTrace(); &#125; return new byte[0]; &#125;&#125;//MethodStackInfo存储方法调用信息public class MethodStackInfo &#123; private String name; private long startTime; private long endTime; private int depth; public MethodStackInfo() &#123; &#125; public MethodStackInfo(String name) &#123; this.name = name; &#125; public MethodStackInfo(String name, long startTime, long endTime, int depth) &#123; this.name = name; this.startTime = startTime; this.endTime = endTime; this.depth = depth; &#125; public String getName() &#123; return name; &#125; public void setName(String name) &#123; this.name = name; &#125; public long getStartTime() &#123; return startTime; &#125; public void setStartTime(long startTime) &#123; this.startTime = startTime; &#125; public long getEndTime() &#123; return endTime; &#125; public void setEndTime(long endTime) &#123; this.endTime = endTime; &#125; public int getDepth() &#123; return depth; &#125; public void setDepth(int depth) &#123; this.depth = depth; &#125;&#125; 修改PreMain方法1234567public class PreMain &#123; public static void premain(String args, Instrumentation instrumentation)&#123; System.out.println("premain"); //新增 instrumentation.addTransformer(new TransformerDemo()); &#125;&#125; 项目打包后通过之前方法测试即可。 遇到的问题1、通过Tomcat启动时获取不到类的字节码解决：因为Tomcat启动时使用多个类加载器作为系统类加载器。这时需要使用insertClassPath来解决 2、部分方法无法修改解决：过滤抽象方法 后续问题1、如果代码中使用循环，最好是能识别出来或者在后续打印过程中去掉2、如果有死循环需要特别处理 这个例子是在main方法启动前，还有get在main方法启动后agentmain。不想在启动时加入VM参数可以参考lombok、stagemonitor的相关实现。 参考： Javassist 使用指南（一） Instrumentation 新功能 利用 Javassist 进行面向方面的更改 Java 5 特性 Instrumentation 实践
